var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"웃기지 말라고, 젠장……!!","JPN":"ふざけないで……！！","ENG":"Oh, give me a break... damn it!","TWN":"別逗了，見鬼……！！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L6_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"대장, 지금 그딴 걸 변명이라고 해!?","JPN":"隊長、それで言い訳のつもり！？","ENG":"Commander, you seriously call that an excuse?","TWN":"隊長，你把那種話當藉口嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 조금만 진정해 주시겠어요, 에이미 양?","JPN":"はは、すこし落ち着いてもらえますか？　エイミーさん。","ENG":"Haha, Amy, could I ask you to relax just a little?","TWN":"哈哈，能稍微冷靜一下嗎，艾米？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"제 말은 아직 안 끝났는데요?","JPN":"僕の話はまだ終わっていません。","ENG":"I wasn't finished.","TWN":"我的話還沒說完呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"진정? 이 상황에서 진정하라고……?","JPN":"落ち着く？　この状況で落ち着けって……？","ENG":"Relax? You want me to relax in this situation...?","TWN":"冷靜？在這種情況下讓我冷靜……？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"날 진정시키려면, 지금부터 내가 묻는 질문에 똑바로 대답해야 할 거야, 대장.","JPN":"あたしに落ち着いてほしかったら、今からする質問にきちんと答えな、隊長。","ENG":"If you want me to relax, then start answering my questions. Right now, Commander.","TWN":"想讓我冷靜下來的話，你必須從現在開始如實回答我的問題，隊長。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"딱 보니까, 대장은 처음부터 스완이 암군의 사도였다는 걸 알고 있었어.","JPN":"見たところ、隊長は最初からスワンが暗君の使徒だって知っていた。","ENG":"It's obvious now that you knew from the beginning that Swan was an Apostle of the Ignorant Monarch.","TWN":"一看就知道，隊長從一開始就知道史旺是暗軍的使徒。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"근데 왜 지금껏 그 사실을 숨기고 계셨을까?","JPN":"なのになんで、今の今までそれを隠していたのかな？　気になるな～","ENG":"Why did you keep it a secret all this time? Huh?","TWN":"可為什麼到現在還隱瞞著這個事實呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"……후후.","JPN":"……ふふ。","ENG":"...Haha.","TWN":"……呵呵。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"웃어?","JPN":"何笑ってんの？","ENG":"How can you be laughing?","TWN":"笑嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"그 팔…….","JPN":"その腕……","ENG":"That arm of yours...","TWN":"那只手……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"잘리고 싶지 않으면, 대장한테서 손 떼는 게 좋을 거야. 금발 원숭이.","JPN":"切り落とされたくなければ、隊長から手を離すんだな。金髪サル。","ENG":"You'd better move it if you don't want it chopped off, Blonde Monkey.","TWN":"不想被解雇的話，最好別碰隊長，金髮猴子。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"선은 넘지 마. 나도 같은 편은 베고 싶지 않으니까.","JPN":"節度を守れ。私もなるべく味方は切りたくない。","ENG":"Don't cross the line. I really don't want to cut down someone on my own side.","TWN":"別越界，我也不想砍同伴。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"시끄러워! 벨 수 있으면, 어디 베 봐……!","JPN":"うるさい！　切れるもんなら、切ってみな……！","ENG":"Shut it! If you think you can cut me, go ahead and try...!","TWN":"吵死了！有本事砍我試試……！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"내가 못 벨 것 같나?","JPN":"出来ないと思うか？","ENG":"Think I can't? You sure about that?","TWN":"你以為我砍不了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"큭큭! 너도 똑같아, 이지수! 그 잘난 눈깔로 미리 다 꿰뚫어 봤을 거 아니야!","JPN":"ククッ！　あんたも同罪だ、ムラサメ・シノ！　そのご自慢の目玉に全部見えていたはずだよね！","ENG":"Haha! You're just the same, Lee Jisoo! You must've seen it all coming with those brilliant eyes of yours!","TWN":"哼哼！你也一樣，李智秀！用你那雙自以為是的眼睛早就看穿了一切吧！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그런데도 지금껏 닥치고 있었던 이유가 뭔데! 설명해!","JPN":"それなのにずっと黙っていた理由はなんだ！　説明しろ！","ENG":"So why didn't you speak up? Tell me!","TWN":"即便如此，你到現在還保持沉默的理由是什麼！解釋一下！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"……바로 지금.","JPN":"……今。","ENG":"...Right now.","TWN":"……就是現在。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"뭐?","JPN":"は？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"대장께서는 바로 지금과 같은 상황을 예측하고, 그 여자에 관한 비밀을 함구해왔던 거야.","JPN":"隊長は今のこのような状況を見越し、あの女の情報を秘密にすると決めた。","ENG":"He saw this coming. That's why he kept her a secret from you.","TWN":"隊長正是預料到了現在這樣的情況，才對那個女人的秘密守口如瓶的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"네놈이 그 여자에 대해 알게 되면, 분명히 성난 원숭이 꼴 마냥 날뛸 게 뻔하니까.","JPN":"お前があの女について知ったら、きっと怒り狂ったサルのごとく暴れ散らかすだろうからな。","ENG":"He figured the second you learned the truth, you'd lose it, like an angry monkey on a rampage.","TWN":"你要是知道了那個女人的事，肯定會像發瘋的猴子一樣亂跳。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"바로 지금 네 꼴처럼.","JPN":"まさに今みたいに。","ENG":"And here you are, proving him right.","TWN":"就像現在的你一樣。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아하, 그려셔~?","JPN":"ほお、なるほど～？","ENG":"Oh, is that so?","TWN":"啊哈～是嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그럼, 그 덕분에 그 여자한테 칼빵 맞고, 우주 깜빵 신세지게 된 것도 예측하셨나 보네?","JPN":"じゃあ、そのおかげであの女にお腹刺されて、宇宙刑務所に入れられるのも見越していたんだろうな？","ENG":"So what, did he also predict I'd get stabbed and thrown into a space prison thanks to her?","TWN":"那麼，你是不是也預見到了因為那個女人而被捅刀子，最後進了宇宙監獄的下場？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"글쎄? 그건 네 실력의 문제 아닐까?","JPN":"さあ？　それはお前の実力問題じゃないか？","ENG":"Oh, please. That sounds more like your own incompetence.","TWN":"哎呀？那不是你的實力問題嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"나였다면, 그렇게 한심하게 당하지는 않아.","JPN":"私なら、そんな情けない真似はしない。","ENG":"If it were me, I wouldn't have gone down so embarrassingly.","TWN":"如果是我的話，不會那麼不堪一擊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"큭큭, 정말? 내가 듣기로는 그 여자를 두 번이나 놓쳤다던데?","JPN":"ククッ、本当かな？　聞くところによると、あの女をもう2回も逃しているらしいけど？","ENG":"Haha, really? Last I heard, you let her escape, twice!","TWN":"呵呵，真的嗎？我聽說你已經兩次放走那個女人了？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"……큭.","JPN":"……くっ。","ENG":"...Krgh.","TWN":"……咳。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"어디였더라? 샤레이드로 밀항하려 했다면서……?","JPN":"どこだっけ？　シャレードに密航しようとしていたとか……","ENG":"Where was it again...? Heard you tried smuggling yourself into Charade…?","TWN":"是哪裡來著？說是要偷渡到查雷德……？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"혹시 배편이라도 잘못 끊은 거 아니야? 너 그런 거 잘 못하잖아?","JPN":"もしかしてチケットの予約、ミスったんじゃない？　あんた、そういうの苦手じゃん？","ENG":"Don't tell me you booked the wrong ship or something? Not like you're good at that sort of thing.","TWN":"不會是訂錯船票了吧？你不是不擅長這種事嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"어디 한 번 계속 떠들어 봐, 금발 원숭이.","JPN":"そのまま続けてみろ、金髪サル。","ENG":"Go on, keep talking, Blonde Monkey. Let's see what happens.","TWN":"繼續吵鬧吧，金髮猴子。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"왜? 더 하라면 못할 줄 알고? 후회할 텐데?","JPN":"はっ、そんなにもっと聞きたい？　後悔するよ？","ENG":"What's wrong? Thought I'd back off? You'll be sorry.","TWN":"怎麼？以為我不能繼續嗎？你會後悔的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"지수 씨, 칼을 거두세요.","JPN":"シノさん、刀を収めてください。","ENG":"Jisoo, lower your weapon.","TWN":"李智秀，收起刀吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"그, 그렇지만 대장! 저 원숭이가 먼저……!","JPN":"で、ですが隊長！　あのサルが先に……！","ENG":"B-but Commander! That monkey started it...!","TWN":"是、是沒錯，可是隊長！是那只猴子先動手的……！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"뭐, 이번 건은 제 설명이 부족했던 게 사실이니까요.","JPN":"まあ、今回の件に関しては、確かに僕の説明不足でしたし。","ENG":"Well, to be fair, I could've explained things better.","TWN":"嗯，這次確實是我解釋不夠清楚。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"저 때문에 두 분께서 싸우는 걸 보니, 마음이 아파서요.","JPN":"僕のせいでお二方が揉めてしまうと、心苦しいのです。","ENG":"Seeing the two of you argue because of me... it honestly hurts.","TWN":"看到你們兩個因為我而爭吵，我感到很難過。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"……알겠습니다.","JPN":"……わかりました。","ENG":"...Fine. I get it.","TWN":"……我知道了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"쳇, 웃기고 자빠졌네.","JPN":"チッ、ふざけんな。","ENG":"Tch. This is such a joke.","TWN":"嘖，簡直笑死人了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"에이미 양, 지수 씨의 말이 맞습니다.","JPN":"エイミーさん、シノさんが話したとおりです。","ENG":"Amy, Jisoo is right.","TWN":"艾米，智秀說得對。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"저는 지수 씨를 통해, 스완의 과거를 전해 듣게 되었고.","JPN":"僕はシノさんを通してスワンの過去を聞き、","ENG":"It was through her that I learned about Swan's past.","TWN":"我透過李智秀，聽說了史旺的過去。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그녀가 타기리온과 사도 계약을 맺었다는 사실을 예전부터 알고 있었어요.","JPN":"彼女がタギリオンと使徒の契約を結んでいることを、以前から知っていました。","ENG":"And yes, I've known for some time that she made a contract with Thagirion to become an Apostle.","TWN":"我早就知道她和塔基里翁簽訂了使徒契約。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아니요. 오히려 알고 있었기 때문에 그녀를 육익의 통제 하에 둬야 한다고 판단했습니다.","JPN":"いいえ、知っていたからこそ、彼女を六翼の目の届くところに置いておく必要があると判断しました。","ENG":"No. In fact, it's precisely because I knew that I believed she needed to be placed under the control of the Six Wings.","TWN":"不，正因為知道，所以才判斷她必須在六翼的控制之下。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그 과정에서 본의 아니게, 당신에게 진실을 감추는 모양새가 되었지만 말이죠.","JPN":"その過程で不本意ながら、あなたに真実を隠す形にはなってしまいましたが。","ENG":"In doing so, I unintentionally ended up keeping the truth from you.","TWN":"在這個過程中，不知不覺間，我似乎對你隱瞞了真相。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"지금 그게 변명이 된다고 생각해?","JPN":"そんな言い訳で納得しろと？","ENG":"And you think that counts as an excuse?","TWN":"你覺得這算是辯解嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L17_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"변명할 생각은 없어요.","JPN":"言い訳をするつもりはありません。","ENG":"It wasn't meant to be one.","TWN":"我不打算找藉口。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"또한 당신 세계에 있었던 일은 진심으로 애석하게 생각합니다, 에이미.","JPN":"また、あなたの世界での出来事については、心から気の毒に思っています。エイミーさん。","ENG":"Also, what happened in your world... I'm truly sorry for it, Amy.","TWN":"另外，我對你們世界發生的事情深感遺憾，艾米。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하지만 당신도 알다시피, 육익은 언제나 <color=#ffd34c>대의</color>를 위해 움직이죠.","JPN":"しかしあなたもご存じのように、六翼はいつも<color=#ffd34c>大義</color>のために動きます。","ENG":"But you know as well as I do. The Six Wings have always acted in the name of the <color=#ffd34c>greater cause</color>.","TWN":"但是你也知道，六翼總是為了<color=#ffd34c>大義</color>而行動。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그리고 그녀 또한 그 대의를 위해 필요한 존재였습니다.","JPN":"そして彼女もまた、その大義のために必要な存在でした。","ENG":"And she was necessary for that greater cause.","TWN":"而她也是為了那份大義所需的存在。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이걸로 설명이 부족할까요?","JPN":"この説明では足りませんか？","ENG":"Still not enough of an explanation for you?","TWN":"這個說明不夠嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"제길, 마음에 안 들어…….","JPN":"くそ、気に食わねえ……","ENG":"Shucks, I don't like this one bit.","TWN":"可惡，我不喜歡……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"후우…! 그래, 좋다 이거야……! 그래서? 대책은 있겠지?","JPN":"ふう……！　ああ、いいさ……！　それで？　対策はあるんだろうね？","ENG":"Hah...! Fine, whatever. So? You've got a plan, right?","TWN":"呼……！好吧，這樣也行……！那麼？有對策了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"대장이라면, 그 망할 년이 어디에 있을지 대강 짐작하고 있을 것 같은데?","JPN":"隊長なら、あのクソ女がどこにいるのか、ある程度予想がついていそうだけど？","ENG":"If anyone has a hunch where she is, it's you.","TWN":"作為隊長，你應該大概能猜到那個該死的女人在哪裡吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"물론이에요.","JPN":"ええ、もちろんです。","ENG":"Of course.","TWN":"當然。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하지만 그 전에 먼저 짚고 넘어가야 할 점이 있습니다.","JPN":"しかしその前にまず1つ、確かめることがあります。","ENG":"But first, there's something we need to address.","TWN":"不過在那之前，有件事必須先說明一下。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"또 뭔데 그렇게 무게를 잡아? 중요한 거야?","JPN":"また何、そんなに改まって。大事なこと？","ENG":"What now? Why the dramatic pause? Is it actually important?","TWN":"又怎麼了？你為什麼這麼嚴肅？很重要嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그렇습니다. 현시점에서 교차 검증을 진행할 수 있는 사람이 당신밖에 없거든요.","JPN":"はい、そうです。現時点でクロスチェックが行える人が、あなたしかいないのです。","ENG":"Yes. At this point, you are the only one who can cross-check things.","TWN":"是的，現階段能進行交叉驗證的人只有你了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"교차 검증이라고?","JPN":"クロスチェック？","ENG":"Cross-check... what exactly?","TWN":"交叉驗證嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"구 관리국 시절, 정보 오염에 대처하는 고전적인 방법이죠.","JPN":"旧管理局時代に行われていた、情報汚染に対処するための古い方法です。","ENG":"It's a classic method from the Old Administration, used to deal with data corruption.","TWN":"舊管理局時期，處理資訊污染的經典方法。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"정보 오염의 급수, 발생 장소, 영향 범위 등등…….","JPN":"情報汚染のレベル、発生場所、影響範囲など……","ENG":"The data corruption level, point of origin, affected area, and so on...","TWN":"資訊污染的等級、發生地點、影響範圍等等……"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"정보 오염이 발생하면, 여러 요인에 의해 사람마다 기억의 차이가 발생할 수 있거든요.","JPN":"情報汚染が発生すれば、様々な要因によって人々の記憶に相違が現れる可能性があります。","ENG":"When data corruption occurs, individual memories can vary due to different influencing factors.","TWN":"如果發生資訊污染，出於各種因素，每個人的記憶可能會有所不同。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그 차이를 서로 검증해가며, 정보의 신뢰도를 최대한 높이는 방법입니다.","JPN":"その差異を比較して、情報の信頼性を最大限高めるのです。","ENG":"So by cross-checking those discrepancies, we can piece together the most reliable version of the truth.","TWN":"交叉驗證就是透過相互驗證這些差異，盡可能提高資訊的可信度的方法。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그렇다면 내가 자리를 비운 사이에 어떤 정보 오염이 발생했다는 거야?","JPN":"ということは、あたしが席を外していた間、何らかの情報汚染が発生したってこと？","ENG":"Then you're saying some kind of data corruption occurred while I was away?","TWN":"那麼在我離開的這段時間裡，是發生了什麼資訊污染嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"네, 그럴 가능성이 매우 높습니다.","JPN":"はい、その可能性が極めて高いです。","ENG":"Yes. That's highly likely.","TWN":"是的，這種可能性非常高。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"왜냐하면, 제 시점에서는 조금 납득하기 힘든 현상이 발생해 버렸거든요.","JPN":"なぜなら、僕の視点からはいささか納得しがたい現象が起きているので。","ENG":"Because from my perspective, something happened that's difficult to accept.","TWN":"因為在我看來，發生了一些難以理解的現象。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"대장이 납득하기 힘든 현상이라고? 흥! 그거 재밌겠는데?","JPN":"隊長が納得できない現象だって？　ふん！　面白そうじゃん！","ENG":"Something even you couldn't accept? Now that sounds interesting!","TWN":"隊長說這是令人費解的現象？哼！那可真有趣！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L47_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"자, 그럼 교차 검증을 시작해 볼까요?","JPN":"さあ、それではクロスチェックを始めましょうか。","ENG":"All right then, shall we begin the cross-check?","TWN":"那麼，我們開始交叉驗證吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"클리포트 게임이 끝나는 순간, 당신과 스완은 세계의 개변을 목격했을 겁니다.","JPN":"クリフォトゲームが終わった瞬間、あなたとスワンは世界の改変を目撃しているはずです。","ENG":"At the moment the Qliphoth Game ended, you and Swan must've witnessed a change in the world.","TWN":"逆卡巴拉遊戲結束的瞬間，你和史旺將目睹世界的變革。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"제 기억에 따르면, 스완은 세계 개변의 장소를 특정했어요.","JPN":"僕の記憶によると、スワンは世界改変の場所を特定していました。","ENG":"According to my memory, Swan identified the exact location where the change happened.","TWN":"據我所知，史旺已經確定了世界變革的地點。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그 장소는 샤레이드와 로터스 사이의 관리 경계 구역… 맞나요?","JPN":"その場所は、シャレードとロータスの間にある管理警戒区域……で合ってますか？","ENG":"It was the Charade-Lotus perimeter zone... right?","TWN":"那個地方是查雷德和洛德斯之間的管理邊界區域……對嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"맞아. 그 장소는 개기일식으로 해가 달에 의해 완전히 가려지는 곳이었어.","JPN":"合ってる。そこは皆既日食によって、月が太陽を完全に隠す場所だった。","ENG":"Yeah. A place where a total solar eclipse blocked the sun completely.","TWN":"沒錯，那個地方是日全食時太陽被月亮完全遮住的地方。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"스완이 뭐라고 했더라? 달의 뒷면에 있는 세피라를 관측할 수 있는 곳이라고 했나?","JPN":"スワンがなんて言ってたっけ？　月の裏側にあるセフィラを観測できる場所って言ったっけ？","ENG":"What did Swan say again? Something about it being the one place where you could observe the Sephira on the dark side of the moon?","TWN":"史旺說什麼來著？是說可以觀測到月球背面的生命樹的地方嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"달의 뒷면과 세피라…….","JPN":"月の裏側とセフィラ……","ENG":"The dark side of the moon and Sephira...","TWN":"月之背面與生命樹……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그렇군요. 이해했습니다. 그 다음에는 어떻게 됐죠?","JPN":"なるほど、理解しました。その後はどうなりましたか？","ENG":"I see. Understood. And what happened after that?","TWN":"原來如此，我了解了。然後呢？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아무튼 그러다가 달이 번쩍하더니, 우리가 있던 침식지대의 자연 환경이 갑자기 바뀌었어.","JPN":"とにかくそれで、月が光ったと思ったら、あたしたちがいた侵食地帯の自然環境がいきなり変わったんだ。","ENG":"Well, the moon suddenly lit up, and the entire natural environment in the Corrupted Area we were in just shifted.","TWN":"總之，月亮突然閃了一下，我們所在的侵蝕地帶的自然環境突然改變了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그 다음, 정체불명의 침식체들이 나타났고, 그걸 본 스완이 돌변해서 배신을 때렸지.","JPN":"それから謎の侵食体たちが現れて、それを見たスワンが急に態度を変えて裏切ったわけ。","ENG":"Then, these unidentified C.O.s showed up... and Swan betrayed us on the spot.","TWN":"接著，不明身份的侵蝕體出現了，看到這一幕的史旺突然變臉，背叛了我們。"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"……자연 환경이 변했다는 건, 무언가 현실 개변이 발생했다는 뜻이로군요.","JPN":"……自然環境が変わったのなら、何らかの現実改変が起こったという意味でしょう。","ENG":"...A sudden environmental change? Sounds like a case of a change in reality has occurred.","TWN":"……自然環境發生了變化，意味著現實中發生了某種改變。"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"침식지대가 자연적으로 회복하는 데에는 무척 오랜 시간이 걸리니까요.","JPN":"侵食地帯が自然回復するには、とても長い時間がかかりますから。","ENG":"Normally, Corrupted Areas take a long time to recover naturally.","TWN":"侵蝕地帶自然恢復需要非常長的時間。"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그렇다면 아마도…….","JPN":"となると……","ENG":"If that's the case, then perhaps...","TWN":"這樣的話或許……"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"흐음. 좋아요. 이쯤에서 교차 검증은 마치도록 할까요?","JPN":"ふむ、いいでしょう。これでクロスチェックは終わりにしましょう。","ENG":"Well then. I believe we can end the cross-check here.","TWN":"嗯，好的，我們就到這裡結束交叉驗證吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"뭐야, 교차 검증이라면서? 벌써 끝이라고? 뭔가 알아낸 거야?","JPN":"なんだ、クロスチェックなのにもう終わり？　なんかわかったの？","ENG":"What? That's it? I thought this was supposed to be a cross-check. But it's already done? Did you figure something out?","TWN":"什麼啊，不是說要交叉驗證嗎？這麼快就結束了？發現什麼了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"네, 이제야 좀 맥락을 알 것 같네요.","JPN":"はい、やっと流れが見えてきました。","ENG":"Yes. I think I finally understand the bigger picture.","TWN":"是，現在我好像明白一些了。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"클리포트 게임이 끝나고, 저희가 자리를 비운 사이 세계에 어떤 변화가 있었는지…….","JPN":"クリフォトゲームが終わり、僕たちが席を外していた間、世界にどのような変化があったのか……","ENG":"What changed in the world after the Qliphoth Game ended, while we were away...","TWN":"逆卡巴拉遊戲結束後，我們離開這期間，世界發生了什麼變化……"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그리고 어째서 현실에 <color=#ffd34c>나타나면 안 되는 것</color>이 나타났는지…….","JPN":"そしてどうして現実に<color=#ffd34c>現れてはいけないもの</color>が現れたのか……","ENG":"And why <color=#ffd34c>something that should never have appeared</color> has shown up in reality...","TWN":"但是為什麼<color=#ffd34c>不該出現在現實中的東西</color>會出現……"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"나타나면 안 되는 것이라고?","JPN":"現れてはいけないもの？","ENG":"Something that should never have appeared?","TWN":"不可以出現的事嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"에이미 양, 이걸 한 번 봐주시겠어요?","JPN":"エイミーさん、ちょっとこれを見ていただけますか？","ENG":"Amy, would you take a look at this?","TWN":"艾米，請看一下這個好嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이 영상은 당신과 스완이 세계의 개변을 목격했던 장소…….","JPN":"この映像はあなたとスワンが世界の改変を目撃した場所……","ENG":"This footage was captured at the site where you and Swan witnessed the change in the world...","TWN":"這個影片是你和史旺目睹世界變革的地方……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"샤레이드와 로터스의 관리 경계 구역의 상공을 촬영한 영상입니다.","JPN":"シャレードとロータスの管理警戒区域の上空を撮影したものです。","ENG":"It's an aerial recording of the Charade-Lotus perimeter zone.","TWN":"這是拍攝的查雷德和洛德斯管理邊界區域的上空影片。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"이, 이건 또 뭐야……?","JPN":"な、なんだこれ……？","ENG":"W-what the hell is this...?","TWN":"這、這又是什麼……？"},"stage":{"bg":"MS_1407","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"이건… 우주선이잖아……?","JPN":"これって……宇宙船じゃん……？","ENG":"This is... a spaceship, isn't it...?","TWN":"這是……太空船……？"},"stage":{"bg":"MS_1407","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};